void spiralFill(int m, int n, std::vector<std::vector<int>>& a) {
    int val = 1;
    int k = 0, l = 0; // k: top row, l: left column
    while (k < m && l < n) {
        // Fill top row from left to right
        for (int i = l; i < n; ++i) {
            a[k][i] = val++;
        }
        k++;
        // Fill right column from top to bottom
        for (int i = k; i < m; ++i) {
            a[i][n-1] = val++;
        }
        n--;
        // Fill bottom row from right to left
        if (k < m) {
            for (int i = n-1; i >= l; --i) {
                a[m-1][i] = val++;
            }
            m--;
        }
        // Fill left column from bottom to top
        if (l < n) {
            for (int i = m-1; i >= k; --i) {
                a[i][l] = val++;
            }
            l++;
        }
    }
}

