int findSubsequenceCount(std::string S, std::string T) {
    int m = T.length();
    int n = S.length();
    if (m > n) 
        return 0;
    // Create a 2D vector with dimensions (m+1) x (n+1) initialized to 0
    std::vector<std::vector<int>> mat(m + 1, std::vector<int>(n + 1, 0));
    // Base case: for j from 0 to n, mat[0][j] = 1 (empty subsequence)
    for (int j = 0; j <= n; j++) {
        mat[0][j] = 1;
    }
    // Note: for i>=1, mat[i][0] is already 0 by initialization
    // Fill the DP table
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (T[i - 1] != S[j - 1]) {
                mat[i][j] = mat[i][j - 1];
            } else {
                mat[i][j] = mat[i][j - 1] + mat[i - 1][j - 1];
            }
        }
    }
    return mat[m][n];
}

