    // If k is 0, return 0 (though k should be at least 1 in this context)
    if (k == 0) return 0;
    // Create a 2D vector dp with dimensions k x n, initialized to 0
    vector<vector<int>> dp(k, vector<int>(n, 0));
    int sum = 0;
    // Base case: for subsequences of length 1
    for (int i = 0; i < n; i++) {
        dp[0][i] = 1;
    }
    // Build the dp table for lengths from 2 to k
    for (int l = 1; l < k; l++) {
        for (int i = l; i < n; i++) {
            dp[l][i] = 0; // Initialize to 0 (though already zero-initialized)
            // Look at all previous elements j from l-1 to i-1
            for (int j = l - 1; j < i; j++) {
                if (arr[j] < arr[i]) {
                    dp[l][i] += dp[l - 1][j];
                }
            }
        }
    }
    // Sum the last row (subsequences of length k ending at each possible index)
    for (int i = k - 1; i < n; i++) {
        sum += dp[k - 1][i];
    }
    return sum;
}

