int countParenth(char symb[], char oper[], int n) {
    if (n == 0) 
        return 0;
    vector<vector<int>> T(n, vector<int>(n, 0));
    vector<vector<int>> F(n, vector<int>(n, 0));
    // Initialize the diagonal elements
    for (int i = 0; i < n; i++) {
        T[i][i] = (symb[i] == 'T') ? 1 : 0;
        F[i][i] = (symb[i] == 'F') ? 1 : 0;
    }
    // Fill the DP table for subexpressions of increasing length
    for (int gap = 1; gap < n; ++gap) {
        for (int i = 0, j = gap; j < n; ++i, ++j) {
            T[i][j] = 0;
            F[i][j] = 0;
            // Try all possible splits in the subexpression [i, j]
            for (int g = 0; g < gap; g++) {
                int k = i + g; // k is the split position (operator index)
                int tik = T[i][k] + F[i][k]; // total ways from i to k
                int tkj = T[k+1][j] + F[k+1][j]; // total ways from k+1 to j
                if (oper[k] == '&') {
                    T[i][j] += T[i][k] * T[k+1][j];
                    F[i][j] += (tik * tkj - T[i][k] * T[k+1][j]);
                }
                else if (oper[k] == '|') {
                    F[i][j] += F[i][k] * F[k+1][j];
                    T[i][j] += (tik * tkj - F[i][k] * F[k+1][j]);
                }
                else if (oper[k] == '^') {
                    T[i][j] += T[i][k] * F[k+1][j] + F[i][k] * T[k+1][j];
                    F[i][j] += T[i][k] * T[k+1][j] + F[i][k] * F[k+1][j];
                }
            }
        }
    }
    return T[0][n-1];
}

