bool isSubsetSum(int set[], int n, int sum) {
    // Create a 2D vector with n+1 rows and sum+1 columns, initialized to false
    vector<vector<bool>> subset(n+1, vector<bool>(sum+1, false));
    // For each row, set the first column (sum=0) to true
    for (int i = 0; i <= n; i++) {
        subset[i][0] = true;
    }
    // Explicitly set the first row (i=0) for sum>=1 to false
    for (int j = 1; j <= sum; j++) {
        subset[0][j] = false;
    }
    // Fill the DP table
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= sum; j++) {
            if (j < set[i-1]) {
                subset[i][j] = subset[i-1][j];
            }
            if (j >= set[i-1]) {
                subset[i][j] = subset[i-1][j] || subset[i-1][j - set[i-1]];
            }
        }
    }
    return subset[n][sum];
}

