int binaryMedian(int** m, int r, int c) {
    int max = INT_MIN;
    int min = INT_MAX;
    for (int i = 0; i < r; i++) {
        if (m[i][0] < min)
            min = m[i][0];
        if (m[i][c-1] > max)
            max = m[i][c-1];
    }
    int desired = (r * c + 1) / 2;
    while (min < max) {
        int mid = min + (max - min) / 2;
        int place = 0;
        for (int i = 0; i < r; i++) {
            int* row = m[i];
            int cnt = std::upper_bound(row, row + c, mid) - row;
            place += cnt;
        }
        if (place < desired)
            min = mid + 1;
        else
            max = mid;
    }
    return min;
}

