int findMinNumber(int n) {
    int count = 0, ans = 1;
    // Handle factor 2
    while (n % 2 == 0) {
        count++;
        n /= 2;
    }
    if (count % 2 == 1) {
        ans *= 2;
    }
    // Handle odd factors up to sqrt(n)
    int sqrt_n = static_cast<int>(std::sqrt(n));
    for (int i = 3; i <= sqrt_n; i += 2) {
        count = 0;
        while (n % i == 0) {
            count++;
            n /= i;
        }
        if (count % 2 == 1) {
            ans *= i;
        }
    }
    // Handle remaining prime factor
    if (n > 2) {
        ans *= n;
    }
    return ans;
}

