int MinimumCost(int cost[], int n, int W) {
    vector<int> val;
    vector<int> wt;
    for (int i = 0; i < n; i++) {
        if (cost[i] != -1) {
            val.push_back(cost[i]);
            wt.push_back(i + 1);
