int find_maximum(int a[], int n, int k) {
    std::unordered_map<int, int> b;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        int d = std::min(1 + i, n - i);
        if (b.find(x) == b.end()) {
            b[x] = d;
        } else {
            b[x] = std::min(b[x], d);
        }
    }
    int ans = INT_MAX;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        int complement = k - x;
        if (x != complement && b.find(complement) != b.end()) {
            int candidate = std::max(b[x], b[complement]);
            ans = std::min(ans, candidate);
        }
    }
    return ans;
}

